func:
if (msg.payload && msg.payload.type === 'command') {
    msg.token = msg.payload.token;
    msg.payload = msg.payload.data;
    return msg;
}
return null;

if (!msg.command) {
  msg.command = msg.payload;
}

const token = msg.token ||
  (msg.req?.headers?.authorization || '').replace('Bearer ', '');

if (!token) {
  node.warn('Command received with no token - ignoring');
  return null;
}

const cache = flow.get('tokenCache') || {};
const cached = cache[token];
if (cached && cached.expires > Date.now()) {
  msg.payload = cached.user;
  return [msg, null];
}

msg._fbToken = token;
msg.payload = { idToken: token };
msg.headers = { 'Content-Type': 'application/json' };
return [null, msg];

if (!msg.payload?.users?.length) {
  node.send([null, { ...msg, statusCode: 401, payload: { error: 'invalid_token' } }]);
  return null;
}

try {
  const firebaseUser = msg.payload.users[0];

  let claims = {};
  try { claims = JSON.parse(firebaseUser.customAttributes || '{}'); } catch (_) {}

  const user = {
    uid: firebaseUser.localId || '',
    username: claims.username || '',
    clientId: claims.clientId || '',
    role: claims.role || 'user',
    commands: claims.commands || {}
  };

  const cache = flow.get('tokenCache') || {};
  const now = Date.now();
  cache[msg._fbToken] = { user, expires: now + (55 * 60 * 1000) };
  Object.keys(cache).forEach((k) => {
    if (cache[k].expires < now) delete cache[k];
  });
  flow.set('tokenCache', cache);

  msg.payload = user;
  return [msg, null];
} catch (e) {
  node.send([null, { ...msg, statusCode: 401, payload: { error: 'invalid_token' } }]);
  return null;
}

const user = msg.payload || {};
const command = msg.command || {};

const ACTION_TO_PERMISSION = {
  'eject specific': 'eject',
  'eject all': 'eject',
  'eject full': 'eject',
  'eject empty': 'eject',
  'eject locked': 'eject',
  'eject module': 'eject',
  'eject count': 'eject',
  'rent': 'eject',
  'vend': 'eject',
  'refund': 'eject',
  'lock slot': 'lock',
  'unlock slot': 'lock',
  'reboot': 'reboot',
  'reload ui': 'reload',
  'ngrok connect': 'connectivity',
  'ngrok disconnect': 'connectivity',
  'hotspot': 'connectivity',
  'update flow': 'updates',
  'update ui': 'updates',
  'disable': 'disable',
  'enable': 'disable',
  'infochange': 'client edit',
  'hardwarechange': 'client edit',
  'pricechange': 'client edit',
  'uichange': 'client edit',
  'provision': 'edit'
};

const requiredPerm = ACTION_TO_PERMISSION[String(command.action || '')];
const userCommands = user.commands || {};
const isAdmin = user.role === 'admin' || user.username === 'chargerent';

if (!isAdmin && requiredPerm && userCommands[requiredPerm] !== true) {
  return [null, null, { _session: msg._session, payload: { status: 'error', reason: 'Permission denied' } }];
}

if (isAdmin) {
  return [msg, null, null];
}

const stationid = String(command.stationid || command.kiosk?.stationid || '').trim();
if (!stationid) {
  return [null, null, { _session: msg._session, payload: { status: 'error', reason: 'Kiosk not found' } }];
}

msg._authContext = {
  user,
  command,
  stationid
};
msg.payload = {
  path: 'kiosks',
  query: [{ fieldPath: 'stationid', opStr: '==', value: stationid }]
};
return [null, msg, null];

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const ctx = msg._authContext || {};
const user = ctx.user || {};
const command = ctx.command || {};

if (docs.length === 0) {
  return [null, { _session: msg._session, payload: { status: 'error', reason: 'Kiosk not found' } }];
}

const kiosk = docs[0] || {};
const info = kiosk.info || {};
const normalize = (value) => String(value || '').trim().toLowerCase();

const userClientId = normalize(user.clientId);
const kioskClient = normalize(info.client || info.clientId);
const kioskRep = normalize(info.rep);
const clientMatch = !!(userClientId && (kioskClient === userClientId || kioskRep === userClientId));

if (!clientMatch) {
  return [null, { _session: msg._session, payload: { status: 'error', reason: 'Unauthorized' } }];
}

msg.payload = user;
msg.command = command;
return [msg, null];
